import { useNavigate } from "react-router-dom";
import { useEffect } from "react";
import "./styles/Home.css";

function Home() {
  const navigate = useNavigate();

  // scroll reveal
  useEffect(() => {
    const reveals = document.querySelectorAll(".reveal");

    const revealOnScroll = () => {
      reveals.forEach((el) => {
        const top = el.getBoundingClientRect().top;
        if (top < window.innerHeight - 100) {
          el.classList.add("active");
        }
      });
    };

    window.addEventListener("scroll", revealOnScroll);
    revealOnScroll();

    return () => window.removeEventListener("scroll", revealOnScroll);
  }, []);

  return (
    <div className="home-page">
      {/* HERO SECTION */}
      <div className="home-hero">
        <div className="hero-text reveal">
          <h1>
            Where <br />
            stories <br />
            <span>sleep in shelves.</span>
          </h1>

          <p>
            Welcome to a quiet corner of magic. A digital sanctuary where
            books are preserved, discovered, and cared for.
          </p>

          <button
            className="enter-btn"
            onClick={() => navigate("/auth")}
          >
            ENTER THE ARCHIVES
          </button>
        </div>

        <div className="hero-images">
          <img
            src="https://images.unsplash.com/photo-1524995997946-a1c2e315a42f"
            alt="Library shelves"
            className="hero-img float"
          />

          <img
            src="https://images.unsplash.com/photo-1507842217343-583bb7270b66"
            alt="Library corridor"
            className="hero-img float delay"
          />
        </div>
      </div>

      {/* ABOUT SECTION */}
      <section className="about-section reveal">
        <h2>About the Archive</h2>
        <p>
          BookSphere is a digital library management system designed to
          bring calm order to knowledge. It connects students, librarians,
          and collections in one thoughtful space.
        </p>

        <div className="about-cards">
          <div className="about-card">📚 Curated Collections</div>
          <div className="about-card">🧑‍🎓 Student Access</div>
          <div className="about-card">🗂 Librarian Control</div>
        </div>
      </section>

      {/* QUOTE */}
      <div className="quote-box reveal">
        <p>“A room without books is like a body without a soul.”</p>
      </div>

      {/* FOOTER */}
      <div className="home-footer">
        <span>BookSphere • Est. MMXXVI</span>
      </div>
    </div>
  );
}

export default Home;
